import java.nio.file.Path;
import java.nio.file.Paths;

// ========= FIXED DownloadServlet.java =========
protected void doGet(HttpServletRequest req, HttpServletResponse resp)
        throws IOException {
    String filename = req.getParameter("file");
    if (filename == null || filename.isEmpty()) {
        resp.sendError(400, "No file specified");
        return;
    }

    // Define the allowed base directory
    Path basePath = Paths.get("web/invoices").toAbsolutePath().normalize();

    // Resolve the requested file and NORMALISE the path
    // normalize() collapses ../ sequences
    Path requestedPath = basePath.resolve(filename).normalize();

    // THE KEY CHECK: Does the resolved path start with our base?
    if (!requestedPath.startsWith(basePath)) {
        resp.sendError(403, "Access denied");
        return;  // Path escapes the allowed directory!
    }

    // Additional: check file exists
    File file = requestedPath.toFile();
    if (!file.exists() || !file.isFile()) {
        resp.sendError(404, "File not found");
        return;
    }

    // Safe to serve the file
    resp.setContentType("application/octet-stream");
    Files.copy(requestedPath, resp.getOutputStream());
}

