// ========= FIXED Error Handling =========
public class ShopErrorHandler extends ErrorHandler {
    private static final Logger log = Logger.getLogger("ShopSecure");

    @Override
    public void handle(String target, Request baseRequest,
            HttpServletRequest req, HttpServletResponse resp) throws IOException {
        int status = resp.getStatus();
        Throwable error = (Throwable) req.getAttribute(
            "javax.servlet.error.exception");

        // LOG detailed info server-side (for developers)
        if (error != null) {
            String errorRef = "ERR-" + System.currentTimeMillis();
            log.severe(String.format("[%s] %s: %s",
                errorRef, error.getClass().getName(), error.getMessage()));
            log.severe(getStackTrace(error));
        }

        // SHOW generic message to user (reveals nothing)
        resp.setContentType("text/html");
        PrintWriter out = resp.getWriter();
        out.print("<h1>Something went wrong</h1>");
        out.print("<p>We've logged this error and will look into it.</p>");
        if (error != null) {
            out.printf("<p>Reference: %s</p>", errorRef);
        }
        out.print("<a href='/shop/'>Return to Home</a>");
        // NO stack trace, NO class names, NO server info
    }
}

